    56	    public static String[] parseKey(String groupKey) {
    57	        StringBuilder sb = new StringBuilder();
    58	        String dataId = null;
    59	        String group = null;
    60	        String tenant = null;
    61	        
    62	        for (int i = 0; i < groupKey.length(); ++i) {
    63	            char c = groupKey.charAt(i);
    64	            if ('+' == c) {
    65	                if (null == dataId) {
    66	                    dataId = sb.toString();
    67	                    sb.setLength(0);
    68	                } else if (null == group) {
    69	                    group = sb.toString();
    70	                    sb.setLength(0);
    71	                } else {
    72	                    throw new IllegalArgumentException("invalid groupkey:" + groupKey);
    73	                }
    74	            } else if ('%' == c) {
    75	                char next = groupKey.charAt(++i);
    76	                char nextnext = groupKey.charAt(++i);
    77	                if ('2' == next && 'B' == nextnext) {
    78	                    sb.append('+');
    79	                } else if ('2' == next && '5' == nextnext) {
    80	                    sb.append('%');
    81	                } else {
    82	                    throw new IllegalArgumentException("invalid groupkey:" + groupKey);
    83	                }
    84	            } else {
    85	                sb.append(c);
    86	            }
    87	        }
    88	        
    89	        if (StringUtils.isBlank(group)) {
    90	            group = sb.toString();
    91	        } else {
    92	            tenant = sb.toString();
    93	        }
    94	        if (group.length() == 0) {
    95	            throw new IllegalArgumentException("invalid groupkey:" + groupKey);
    96	        }
    97	    
