package com.alibaba.nacos.config.server.utils;

import com.alibaba.nacos.config.server.constant.Constants;
import org.junit.jupiter.api.Test;

import java.util.ArrayList;
import java.util.List;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

class ZipUtilsTest {

    @Test
    void testZip() {
        List<ZipUtils.ZipItem> zipItemList = new ArrayList<>();
        zipItemList.add(new ZipUtils.ZipItem("test", "content"));
        byte[] zip = ZipUtils.zip(zipItemList);
        assertTrue(zip != null && zip.length > 0);
    }

    @Test
    void testUnzip() {

        List<ZipUtils.ZipItem> zipItemList = new ArrayList<>();
        zipItemList.add(new ZipUtils.ZipItem("test", "content"));
        byte[] zip = ZipUtils.zip(zipItemList);
        assertTrue(zip != null && zip.length > 0);

        ZipUtils.UnZipResult unZipResult = ZipUtils.unzip(zip);
        List<ZipUtils.ZipItem> result = unZipResult.getZipItemList();
        assertEquals(zipItemList.size(), result.size());
        assertEquals(zipItemList.get(0).getItemName(), result.get(0).getItemName());
        assertEquals(zipItemList.get(0).getItemData(), result.get(0).getItemData());

    }

    @Test
    void testUnzipWithMetadata() {
        List<ZipUtils.ZipItem> zipItemList = new ArrayList<>();
        zipItemList.add(new ZipUtils.ZipItem("DEFAULT_GROUP/application.yml", "test: content"));
        zipItemList.add(new ZipUtils.ZipItem(Constants.CONFIG_EXPORT_METADATA_NEW, "metadata content"));
        byte[] zip = ZipUtils.zip(zipItemList);

        ZipUtils.UnZipResult unZipResult = ZipUtils.unzip(zip);
        assertNotNull(unZipResult.getMetaDataItem());
        assertEquals(Constants.CONFIG_EXPORT_METADATA_NEW, unZipResult.getMetaDataItem().getItemName());
        assertEquals("metadata content", unZipResult.getMetaDataItem().getItemData());
        assertEquals(1, unZipResult.getZipItemList().size());
    }

    @Test
    void testUnzipWithOldMetadata() {
        List<ZipUtils.ZipItem> zipItemList = new ArrayList<>();
        zipItemList.add(new ZipUtils.ZipItem("DEFAULT_GROUP/application.yml", "test: content"));
        zipItemList.add(new ZipUtils.ZipItem(Constants.CONFIG_EXPORT_METADATA, "metadata content"));
        byte[] zip = ZipUtils.zip(zipItemList);

        ZipUtils.UnZipResult unZipResult = ZipUtils.unzip(zip);
        assertNotNull(unZipResult.getMetaDataItem());
        assertEquals(Constants.CONFIG_EXPORT_METADATA, unZipResult.getMetaDataItem().getItemName());
        assertEquals("metadata content", unZipResult.getMetaDataItem().getItemData());
        assertEquals(1, unZipResult.getZipItemList().size());
    }

    @Test
    void testUnzipWithMetaDataFile() {
        // Test that the old "meta_data" plain text format is recognized
        List<ZipUtils.ZipItem> zipItemList = new ArrayList<>();
        zipItemList.add(new ZipUtils.ZipItem("DEFAULT_GROUP/application.yml", "test: content"));
        zipItemList.add(new ZipUtils.ZipItem("meta_data", "DEFAULT_GROUP|application.yml|"));
        byte[] zip = ZipUtils.zip(zipItemList);

        ZipUtils.UnZipResult unZipResult = ZipUtils.unzip(zip);
        assertNotNull(unZipResult.getMetaDataItem());
        assertEquals("meta_data", unZipResult.getMetaDataItem().getItemName());
        assertEquals("DEFAULT_GROUP|application.yml|", unZipResult.getMetaDataItem().getItemData());
        assertEquals(1, unZipResult.getZipItemList().size());
    }

    @Test
    void testUnzipWithoutMetadata() {
        // When there is no metadata file, metaDataItem should be null
        List<ZipUtils.ZipItem> zipItemList = new ArrayList<>();
        zipItemList.add(new ZipUtils.ZipItem("DEFAULT_GROUP/application.yml", "test: content"));
        byte[] zip = ZipUtils.zip(zipItemList);

        ZipUtils.UnZipResult unZipResult = ZipUtils.unzip(zip);
        assertNull(unZipResult.getMetaDataItem());
        assertEquals(1, unZipResult.getZipItemList().size());
        assertEquals("DEFAULT_GROUP/application.yml", unZipResult.getZipItemList().get(0).getItemName());
    }
}

